import SideMenu from '@/components/SideMenu.vue'

export default {
  name: 'items',
  props: ['inventory','cart'],
  data () {
    return {
      href: this.$route.params.href,
      items: require('../items.json')
    }
  },
  computed: {
    cartIsValid () {
      return this.inventory.color && this.inventory.qty && this.inventory.size
    }
  },
  methods: {
    check (newinput) {
      var flag = -1
      this.cart.forEach(i => {
        if (i.color === newinput.color && i.size === newinput.size) {
          flag = i.id
        }
      })
      return flag
    },
    addToCart () {
      this.total += this.inventory.qty
      var cartindex = this.check(this.inventory)
      if (cartindex !== -1) {
        this.cart[cartindex].qty = this.cart[cartindex].qty + this.inventory.qty
      } else {
        var temp = { id: 0, color: '', qty: 0, size: '' }
        temp.id = this.inventory.id
        temp.color = './assets/img/new-in/top/top-' + this.inventory.color + '.jpg'
        temp.qty = this.inventory.qty
        temp.size = this.inventory.size
        this.cart.push(temp)
        this.inventory.id++
      }
      this.inventory.qty = 0
      this.cart.forEach(element => {
        console.log(element)
      })
    }
  },
  components: {
    SideMenu
  }
}
